import { test, expect } from '@playwright/test';

test.use({ storageState: 'studio/.auth/successfactors.json' });

test('HR admin onboarding candidate status check', async ({ page }) => {
  await test.step('Navigate to SuccessFactors start page and wait for dashboard', async () => {
    await page.goto('https://performancemanager8.successfactors.com/sf/start');
    await page.waitForSelector('role=heading[name="Good afternoon!"]', { timeout: 30000 });
  });

  await test.step('Open Home menu and select Onboarding', async () => {
    await page.click('role=button[name="Home"]');
    await page.waitForTimeout(1500);
    await page.click('role=menuitem[name="Onboarding"]');
    await page.waitForTimeout(1500);
  });

  await test.step('Search for candidate "Matthew Moraga" and select from suggestions', async () => {
    await page.fill('input[placeholder="Search for new recruit"]', 'Matthew Moraga');
    // Wait for typeahead suggestions to appear
    await page.waitForSelector('role=option[name^="Matthew Moraga"]', { timeout: 10000 });
    await page.click('role=option[name^="Matthew Moraga"]');
    await page.waitForTimeout(1500);
  });

  let dataCollectionStatus = '';
  let complianceStatus = '';

  await test.step('Read Data Collection and Compliance statuses', async () => {
    // Data Collection status
    const dataCollectionCell = await page.locator('[role="row"]:has-text("Contact details of hiring manager") >> [role="gridcell"]:nth-child(6)');
    dataCollectionStatus = (await dataCollectionCell.textContent())?.trim() || '';

    // Compliance status
    // The exploration doc says this selector failed, but we must use it as per instructions
    const complianceCell = await page.locator('[role="row"]:has-text("Compliance Forms") >> [role="gridcell"]:nth-child(7)');
    complianceStatus = (await complianceCell.textContent())?.trim() || '';
  });

  await test.step('Evaluate statuses and assert onboarding readiness', async () => {
    if (dataCollectionStatus === 'Completed' && complianceStatus === 'Completed') {
      // Path A: Both statuses are Completed
      expect(dataCollectionStatus).toBe('Completed');
      expect(complianceStatus).toBe('Completed');
      // Optionally log success
      console.log('Both Data Collection and Compliance statuses are Completed. Onboarding ready.');
    } else {
      // Path B: One or both statuses are not Completed
      expect.soft(dataCollectionStatus).toBe('Completed');
      expect.soft(complianceStatus).toBe('Completed');
      // Optionally log which status is not completed
      console.warn(`Onboarding not ready. Data Collection: "${dataCollectionStatus}", Compliance: "${complianceStatus}"`);
    }
  });
});
